// Calcula rangos de fechas en zona Europe/Madrid (ISO week: lunes-domingo)
const now = new Date();

function madridYMD(d){ return d.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }
function madridDow(d){
  // 0=Lun ... 6=Dom
  const wd = new Intl.DateTimeFormat('en-US', { timeZone:'Europe/Madrid', weekday:'short' }).format(d);
  return ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(wd);
}
function ymdToDate(s){ return new Date(s + 'T00:00:00Z'); }
function ymdFromDate(d){ return d.toISOString().substring(0,10); }
function addDays(s,n){ const d = ymdToDate(s); d.setUTCDate(d.getUTCDate()+n); return ymdFromDate(d); }

const todayYMD     = madridYMD(now);
const daysSinceMon = madridDow(now);
const weekYMD      = addDays(todayYMD, -daysSinceMon);
const lastWeekYMD  = addDays(weekYMD, -7);
const yesterdayYMD = addDays(todayYMD, -1);
const sevenDaysYMD = addDays(todayYMD, -6);
const [yy, mm]     = todayYMD.split('-');
const monthYMD     = `${yy}-${mm}-01`;
// Histórico para medias y sparklines: 28 días atrás → 4 mismos días
// de semana pasados para la media, manteniéndose por debajo del
// límite de 1000 resultados del Search API.
const histYMD      = addDays(todayYMD, -28);
const agedYMD      = addDays(todayYMD, -5);  // umbral 'lleva más de 5 días'
// Los 4 mismos días de semana pasados (para hourly average preciso)
const sw1YMD = addDays(todayYMD, -7);    const sw1End = addDays(todayYMD, -6);
const sw2YMD = addDays(todayYMD, -14);   const sw2End = addDays(todayYMD, -13);
const sw3YMD = addDays(todayYMD, -21);   const sw3End = addDays(todayYMD, -20);
const sw4YMD = addDays(todayYMD, -28);   const sw4End = addDays(todayYMD, -27);

return [{ json: {
  today_ymd:        todayYMD,
  yesterday_ymd:    yesterdayYMD,
  week_ymd:         weekYMD,
  last_week_ymd:    lastWeekYMD,
  seven_days_ymd:   sevenDaysYMD,
  month_ymd:        monthYMD,
  hist_ymd:         histYMD,
  aged_ymd:         agedYMD,
  sw1_ymd: sw1YMD, sw1_end: sw1End,
  sw2_ymd: sw2YMD, sw2_end: sw2End,
  sw3_ymd: sw3YMD, sw3_end: sw3End,
  sw4_ymd: sw4YMD, sw4_end: sw4End,
  now_iso:          now.toISOString()
} }];

const prev = $input.first().json;
const dates = $('Calcular fechas').first().json;
return [{ json: { ...dates, zd_today: prev } }];

// Calcula tiempo medio de primera respuesta (FRT) interseccionando
// los 100 ticket_metrics más recientes con los IDs de los tickets
// manuales creados hoy. Un único HTTP call, robusto.
const acc = $('Guardar Hoy Manual').first().json;
const body = $input.first().json || {};
const metrics = Array.isArray(body.ticket_metrics) ? body.ticket_metrics : [];

// Normalizamos a string para evitar mismatch number vs string
const todayManualIds = new Set(
  ((acc.zd_today_manual && acc.zd_today_manual.results) || [])
    .map(t => t && t.id != null ? String(t.id) : null).filter(Boolean)
);

const todayMetrics = metrics.filter(m => m && m.ticket_id != null && todayManualIds.has(String(m.ticket_id)));

const times = todayMetrics
  .map(m => m && m.reply_time_in_minutes && m.reply_time_in_minutes.calendar)
  .filter(v => typeof v === 'number' && v > 0);

const sample = times.length;
const avgMin = sample ? Math.round(times.reduce((a,b)=>a+b,0) / sample) : null;

return [{ json: {
  ...acc,
  frt_avg_min: avgMin,
  frt_sample: sample,
  _frt_today_ids_size: todayManualIds.size,
  _frt_metrics_size: metrics.length,
  _frt_matched: todayMetrics.length
} }];

// El nodo Zendesk emite un item por ticket. Los agrupamos en zd_hist.
const acc = $('Guardar Hoy Manual').first().json;
const allTickets = $input.all().map(i => i.json).filter(Boolean);
return [{ json: { ...acc, zd_hist: { results: allTickets, count: allTickets.length } } }];

// Consolida los 4 días de semana pasados en zd_past_sw
const acc = $('Guardar SW3').first().json;
const sw4 = $input.first().json || {};
const allResults = [
  ...((acc.zd_sw1 && acc.zd_sw1.results) || []),
  ...((acc.zd_sw2 && acc.zd_sw2.results) || []),
  ...((acc.zd_sw3 && acc.zd_sw3.results) || []),
  ...((sw4.results) || [])
];
return [{ json: { ...acc, zd_sw4: sw4, zd_past_sw: { results: allResults, count: allResults.length } } }];

// Extrae los IDs de las top 8 orgs del MES (filtramos zd_hist a >= month_ymd)
const d = $input.first().json;
const histRes  = (d.zd_hist && Array.isArray(d.zd_hist.results)) ? d.zd_hist.results : [];
const monthYMD = d.month_ymd;
function ymdMad(date){ return date.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }

const orgCount = new Map();
for (const t of histRes) {
  const c = t.created_at || t.createdAt;
  if (!c) continue;
  if (ymdMad(new Date(c)) < monthYMD) continue;
  if (!t.organization_id) continue;
  orgCount.set(t.organization_id, (orgCount.get(t.organization_id) || 0) + 1);
}
const top = [...orgCount.entries()].sort((a,b)=>b[1]-a[1]).slice(0,8);
const ids = new Set(top.map(([id])=>id));

return [{ json: { ...d, org_ids_csv: [...ids].join(',') || '0', top_orgs_raw: top } }];

// Consolida todo en el JSON final
const d = $input.first().json;

function count(obj){
  if (!obj) return 0;
  if (typeof obj.count === 'number') return obj.count;
  if (Array.isArray(obj.results)) return obj.results.length;
  return 0;
}
function results(obj){
  if (!obj || !Array.isArray(obj.results)) return [];
  return obj.results;
}
function ymdMadrid(date){ return date.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }
function partsMadrid(date){
  return new Intl.DateTimeFormat('en-US', {
    timeZone:'Europe/Madrid', weekday:'short', hour:'2-digit', hour12:false
  }).formatToParts(date);
}

const today        = count(d.zd_today);
const yesterday    = count(d.zd_yesterday);
const week         = count(d.zd_week);
const lastWeek     = count(d.zd_last_week);
const open         = count(d.zd_open);
const todayIA       = count(d.zd_today_ia);
const todayManual   = count(d.zd_today_manual);
const yesterdayIA   = count(d.zd_yesterday_ia);
const yesterdayManual = count(d.zd_yesterday_manual);
const solvedToday   = count(d.zd_solved_today);
const backlogToday  = todayManual - solvedToday;

const todayRes = results(d.zd_today);
const openRes  = results(d.zd_open);
const histRes  = results(d.zd_hist);
const pending  = openRes.filter(t => t.status === 'pending').length;

const weekYMD  = d.week_ymd;
const monthYMD = d.month_ymd;

// Tickets de este mes (filtramos histRes a >= month_ymd)
const monthRes = histRes.filter(t => {
  const c = t.created_at || t.createdAt;
  return c && ymdMadrid(new Date(c)) >= monthYMD;
});
const month = monthRes.length;
let monthIA = 0, monthManual = 0;
for (const t of monthRes) {
  const subj = String(t.subject || '').trim().toLowerCase();
  if (subj.startsWith('conversation with')) monthIA++; else monthManual++;
}

// ────── A · HOURLY TODAY vs MEDIA (mismo día semana últimas 4 semanas) ──────
const HOURS_RANGE = ['09','10','11','12','13','14','15','16','17','18'];
const nowD = new Date();
const todayLocalYMD = ymdMadrid(nowD);
const todayWdStr = new Intl.DateTimeFormat('en-US', { timeZone:'Europe/Madrid', weekday:'short' }).format(nowD);

const hoursToday = Object.fromEntries(HOURS_RANGE.map(h => [h, 0]));
for (const t of todayRes) {
  if (!t.created_at) continue;
  const dt = new Date(t.created_at);
  if (ymdMadrid(dt) !== todayLocalYMD) continue;
  const hh = partsMadrid(dt).find(p => p.type === 'hour')?.value || '00';
  if (hoursToday[hh] !== undefined) hoursToday[hh]++;
}

// Media: agrupar tickets de los 4 mismos días de semana pasados
// (dataset dedicado zd_past_sw para esquivar el límite de 1000 de
// Zendesk Search que sufre el dataset histórico general).
const pastSwRes = results(d.zd_past_sw);
const sameWdSums = Object.fromEntries(HOURS_RANGE.map(h => [h, 0]));
const sameWdDaysSeen = new Set();
for (const t of pastSwRes) {
  if (!t.created_at) continue;
  const dt = new Date(t.created_at);
  if (ymdMadrid(dt) === todayLocalYMD) continue;
  sameWdDaysSeen.add(ymdMadrid(dt));
  const p = partsMadrid(dt);
  const hh = p.find(x => x.type === 'hour')?.value || '00';
  if (sameWdSums[hh] !== undefined) sameWdSums[hh]++;
}
// Denominador = nº de días distintos encontrados (típicamente 4); con
// fallback al cálculo por calendario por si algún día tuviera 0 tickets
let sampleDays = sameWdDaysSeen.size;
if (sampleDays === 0) {
  const _histStart = new Date(d.hist_ymd + 'T12:00:00Z');
  const _todayStart = new Date(todayLocalYMD + 'T12:00:00Z');
  for (let dt = new Date(_histStart); dt < _todayStart; dt.setUTCDate(dt.getUTCDate() + 1)) {
    const wd = new Intl.DateTimeFormat('en-US', { timeZone:'Europe/Madrid', weekday:'short' }).format(dt);
    if (wd === todayWdStr) sampleDays++;
  }
  if (sampleDays === 0) sampleDays = 1;
}
const hourly_today = HOURS_RANGE.map(h => ({
  hour: h + ':00',
  today: hoursToday[h],
  avg: Math.round((sameWdSums[h] / sampleDays) * 10) / 10
}));

// ────── C · STACKED IA/MANUAL por día (L-V hasta hoy) ──────
const DAYS_LV = ['Lun','Mar','Mié','Jue','Vie'];
const _wdIdx = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(todayWdStr);
const lastDayIdx = Math.min(_wdIdx, 4);
const visibleDays = DAYS_LV.slice(0, lastDayIdx + 1);
const stackedIA = Object.fromEntries(visibleDays.map(dn => [dn, 0]));
const stackedMa = Object.fromEntries(visibleDays.map(dn => [dn, 0]));
let weekIA = 0, weekMa = 0;
for (const t of histRes) {
  const created = t.created_at || t.createdAt;
  if (!created) continue;
  const dt = new Date(created);
  if (isNaN(dt.getTime())) continue;
  if (ymdMadrid(dt) < weekYMD) continue;
  const p = partsMadrid(dt);
  const wd = p.find(x => x.type === 'weekday')?.value;
  const idx = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(wd);
  if (idx < 0 || idx > 4 || idx > lastDayIdx) continue;
  const dn = DAYS_LV[idx];
  const subj = String(t.subject || '').trim().toLowerCase();
  const isIA = subj.startsWith('conversation with');
  if (isIA) { stackedIA[dn]++; weekIA++; } else { stackedMa[dn]++; weekMa++; }
}
const weekly_stacked = visibleDays.map(dn => ({
  day: dn,
  ia: stackedIA[dn],
  manual: stackedMa[dn],
  total: stackedIA[dn] + stackedMa[dn],
  pct_ia: (stackedIA[dn] + stackedMa[dn]) > 0
    ? Math.round((stackedIA[dn] / (stackedIA[dn] + stackedMa[dn])) * 100) : 0
}));

// ────── Tickets envejecidos (>3 días sin cerrar, sin IA) ──────
const tickets_aged_3d = count(d.zd_aged);

// ────── Top orgs del mes + sparkline 14 días ──────
const orgCount = new Map();
for (const t of monthRes) {
  if (!t.organization_id) continue;
  orgCount.set(t.organization_id, (orgCount.get(t.organization_id) || 0) + 1);
}
const topOrgIds = [...orgCount.entries()].sort((a,b)=>b[1]-a[1]).slice(0,8);

// Construir array de 14 días YMD (oldest -> today)
const dayList = [];
for (let i = 13; i >= 0; i--) {
  const dt = new Date(nowD); dt.setDate(dt.getDate() - i);
  dayList.push(ymdMadrid(dt));
}
const dayIndex = Object.fromEntries(dayList.map((y,i) => [y, i]));

// Por cada org top, contar tickets por día
const sparklineByOrg = new Map();
for (const [orgId] of topOrgIds) sparklineByOrg.set(orgId, new Array(14).fill(0));
for (const t of histRes) {
  if (!t.organization_id) continue;
  if (!sparklineByOrg.has(t.organization_id)) continue;
  const created = t.created_at || t.createdAt;
  if (!created) continue;
  const dYMD = ymdMadrid(new Date(created));
  const idx = dayIndex[dYMD];
  if (idx !== undefined) sparklineByOrg.get(t.organization_id)[idx]++;
}

const orgMap = new Map();
const orgsResolved = (d.zd_orgs && Array.isArray(d.zd_orgs.organizations)) ? d.zd_orgs.organizations : [];
for (const o of orgsResolved) { if (o && o.id) orgMap.set(o.id, o.name); }
function orgName(id){ return orgMap.get(id) || `Organización ${id}`; }

const top_orgs = topOrgIds.map(([id, count]) => ({
  name: orgName(id),
  count,
  sparkline: sparklineByOrg.get(id) || []
}));

return [{ json: {
  generated_at: new Date().toISOString(),
  tickets_today: today,
  tickets_yesterday: yesterday,
  tickets_week: week,
  tickets_last_week: lastWeek,
  tickets_open: open,
  tickets_pending: pending,
  tickets_month: month,
  tickets_solved_today: solvedToday,
  backlog_today: backlogToday,
  frt_avg_min: d.frt_avg_min ?? null,
  frt_sample: d.frt_sample ?? 0,
  _frt_today_ids_size: d._frt_today_ids_size ?? null,
  _frt_metrics_size: d._frt_metrics_size ?? null,
  _frt_matched: d._frt_matched ?? null,
  tickets_aged_3d,
  tickets_today_ia: todayIA,
  tickets_today_manual: todayManual,
  tickets_yesterday_ia: yesterdayIA,
  tickets_yesterday_manual: yesterdayManual,
  tickets_month_ia: monthIA,
  tickets_month_manual: monthManual,
  tickets_week_ia: weekIA,
  tickets_week_manual: weekMa,
  hourly_today,
  weekly_stacked,
  top_orgs
} }];
